features.snippet:
interface inner_if(input clk);
  logic valid;
endinterface

interface outer_if(input clk);
  inner_if sub_if(.clk(clk));
  wire valid = sub_if.valid;
endinterface

module top(output logic valid);
  outer_if oif(.clk(1'b0));
  assign valid = oif.valid;
endmodule

interface simple_if;
  logic [7:0] data;
endinterface

module top;
  simple_if fifo_arr[2:0]();
  wire [7:0] d = fifo_arr[0].data;
endmodule
